/**
 * Custom React Query Mutation Hook
 * 
 * Wrapper around React Query's useMutation that integrates with your existing apiRequest
 * and provides automatic query invalidation for live updates across the app.
 * 
 * @example
 * const { mutate, isLoading, error } = useMutation({
 *   mutationFn: (data) => apiRequest('/endpoint', { method: 'POST', body: JSON.stringify(data) }),
 *   invalidateQueries: [['dashboard-metrics'], ['wallet-balance']],
 *   onSuccess: (data) => {
 *     success('Operation completed!');
 *   },
 * });
 */

import { useMutation as useReactMutation, useQueryClient } from '@tanstack/react-query';
import { apiRequest } from '@/shared/services/apiClient.js';

/**
 * Custom useMutation hook that integrates with your apiRequest and provides automatic query invalidation
 * 
 * @param {Object} options - Mutation options
 * @param {Function|Object} options.mutationFn - Mutation function or service method configuration
 * @param {string} [options.endpoint] - API endpoint (if using service method pattern)
 * @param {Object} [options.apiOptions] - Options to pass to apiRequest (method, body, headers, etc.)
 * @param {Array<string|Array>} [options.invalidateQueries] - Query keys to invalidate after successful mutation
 * @param {Function} [options.onSuccess] - Callback when mutation succeeds (receives data, variables, context)
 * @param {Function} [options.onError] - Callback when mutation fails (receives error, variables, context)
 * @param {boolean} [options.refetchQueries] - Whether to refetch invalidated queries immediately (default: true)
 * @returns {Object} Mutation result with mutate, mutateAsync, isLoading, error, etc.
 */
export function useMutation({
  mutationFn,
  endpoint,
  apiOptions = {},
  invalidateQueries = [],
  onSuccess,
  onError,
  refetchQueries = true,
  ...otherOptions
}) {
  const queryClient = useQueryClient();

  // Build mutation function from endpoint/apiOptions if provided
  const finalMutationFn = mutationFn || (async (variables) => {
    // If variables is an object and we have endpoint, merge variables into apiOptions
    const finalApiOptions = {
      ...apiOptions,
      ...(variables && typeof variables === 'object' && !(variables instanceof FormData)
        ? { body: JSON.stringify(variables) }
        : {}),
    };
    
    return await apiRequest(endpoint, finalApiOptions);
  });

  return useReactMutation({
    mutationFn: finalMutationFn,
    onSuccess: (data, variables, context) => {
      // Invalidate queries to trigger refetch
      if (invalidateQueries && invalidateQueries.length > 0) {
        invalidateQueries.forEach((queryKey) => {
          queryClient.invalidateQueries({
            queryKey: Array.isArray(queryKey) ? queryKey : [queryKey],
            refetchType: refetchQueries ? 'active' : 'none', // Only refetch active queries
          });
        });
      }

      // Call custom onSuccess if provided
      if (onSuccess) {
        onSuccess(data, variables, context);
      }
    },
    onError,
    ...otherOptions,
  });
}

export default useMutation;

